11→public class SpacingAroundRangeOperatorRule : StandardRule("range-spacing") {
12→    override fun beforeVisitChildNodes(
13→        node: ASTNode,
14→        autoCorrect: Boolean,
15→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
16→    ) {
17→        if (node.elementType == RANGE) {
18→            val prevLeaf = node.prevLeaf()
19→            val nextLeaf = node.nextLeaf()
20→            when {
21→                prevLeaf is PsiWhiteSpace && nextLeaf is PsiWhiteSpace -> {
22→                    emit(node.startOffset, "Unexpected spacing around \"..\"", true)
23→                    if (autoCorrect) {
24→                        prevLeaf.node.treeParent.removeChild(prevLeaf.node)
25→                        nextLeaf.node.treeParent.removeChild(nextLeaf.node)
26→                    }
27→                }
28→                prevLeaf is PsiWhiteSpace -> {
29→                    emit(prevLeaf.node.startOffset, "Unexpected spacing before \"..\"", true)
30→                    if (autoCorrect) {
31→                        prevLeaf.node.treeParent.removeChild(prevLeaf.node)
32→                    }
33→                }
34→                nextLeaf is PsiWhiteSpace -> {
35→                    emit(nextLeaf.node.startOffset, "Unexpected spacing after \"..\"", true)
36→                    if (autoCorrect) {
37→                        nextLeaf.node.treeParent.removeChild(nextLeaf.node)
38→                    }
39→                }
40→            }
41→        }
42→    }
43→}
44→
